import { useEffect, useState } from "react";

function App() {

  const [homes, setHomes] = useState([]);

  useEffect(() => {

    const fetchEnergy = () => {
      fetch("http://localhost:5000/energy")
        .then((res) => res.json())
        .then((data) => setHomes(data));
    };

    fetchEnergy();

    const interval = setInterval(fetchEnergy, 3000);

    return () => clearInterval(interval);

  }, []);

  return (

    <div style={{
      padding: "20px",
      fontFamily: "Arial"
    }}>

      <h1>OpenGreenGrid Dashboard</h1>

      {homes.map((home, index) => (

        <div
          key={index}
          style={{
            border: "1px solid gray",
            borderRadius: "10px",
            padding: "15px",
            marginBottom: "15px"
          }}
        >

          <h2>{home.house}</h2>

          <p>
            Generated Power: {home.generatedPower} kWh
          </p>

          <p>
            Consumed Power: {home.consumedPower} kWh
          </p>

          <p>
            Battery Level: {home.batteryLevel}%
          </p>

        </div>

      ))}

    </div>

  );

}

export default App;
